# Zero UUID used by Bambu printers for empty/unset tray_uuid
_ZERO_UUID = "00000000000000000000000000000000"


def _resolve_spool_tag(tray_info: dict) -> str:
    """Get the best spool identifier from tray info (prefer tray_uuid, fallback to filament_id)."""
    tray_uuid = tray_info.get("tray_uuid")
    if tray_uuid and tray_uuid != _ZERO_UUID:
        return tray_uuid
    filament_id = tray_info.get("filament_id")
    if filament_id:
        return filament_id
    return ""


def _parse_gcode_line(line: str):
    """Parse a single G-code line for filament usage commands.

    Returns a tuple (command, value) or (None, None) if not relevant.
    """
    line = line.strip()
    if line.startswith("M117"):  # Example: M117 Filament used: 1234
        parts = line.split()
        for part in parts:
            if part.isdigit():
                return ("M117", int(part))
    elif line.startswith("G1"):  # Example: G1 E123.45
        parts = line.split()
        for part in parts:
            if part.startswith("E"):
                try:
                    value = float(part[1:])
                    return ("G1", value)
                except ValueError:
                    pass
    return (None, None)


def calculate_filament_usage(gcode_lines):
    """Calculate filament usage from G-code lines.

    Returns the total filament used as a float.
    """
    last_e_value = 0.0
    total_used = 0.0
    for line in gcode_lines:
        cmd, val = _parse_gcode_line(line)
        if cmd == "G1" and val is not None:
            if val > last_e_value:
                total_used += val - last_e_value
            last_e_value = val
    return total_used


